#include <iostream>
#include <string>

class Counter {
private:
    int current_val;
    bool is_active_status;
public:
    Counter(int initial_value_param = 0) {
        this->current_val = initial_value_param;
        this->is_active_status = true;
    }

    int getValue() const {
        int temp_retrieved_value = this->current_val;
        return temp_retrieved_value;
    }

    Counter& operator++() {
        this->current_val = this->current_val + 1;
        return *this;
    }

    Counter operator++(int dummy_int_parameter) {
        Counter temporary_copy_before_increment = *this;
        this->current_val = this->current_val + 1;
        return temporary_copy_before_increment;
    }
};

int main() {
    // For test case 1:
    Counter tc1_c(5); 
    std::cout << (++tc1_c).getValue() << std::endl; 
    std::cout << tc1_c.getValue() << std::endl;

    // For test case 2:
    Counter tc2_c(10); 
    std::cout << (tc2_c++).getValue() << std::endl; 
    std::cout << tc2_c.getValue() << std::endl;

    // For test case 3:
    Counter tc3_c(1); 
    ++(++tc3_c); 
    std::cout << tc3_c.getValue() << std::endl;

    return 0;
}
